-- Kitscore database schema baseline -- snapshot as of 2026-07-15
--
-- Generated by querying pg_proc / pg_trigger / pg_policy directly against
-- the live Supabase project (tpcriphrfrrgywycviqv). This is a REFERENCE
-- SNAPSHOT documenting what exists, not a migration meant to be replayed.
-- Supersedes schema-baseline-2026-07-04.sql, which had drifted ~11 days
-- behind live (missing, among other things, creator_collaborations,
-- creator_press_mentions, available_for/causes/theme on creators, and
-- view_count on platform_connections). See README.md in this folder for
-- why this file exists and the practice going forward.

-- =============================================================
-- FUNCTIONS
-- =============================================================

CREATE OR REPLACE FUNCTION public.check_evaluation_completeness()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
DECLARE
  completeness NUMERIC;
BEGIN
  completeness := creator_score_completeness(NEW.creator_id);
  IF completeness < 50 THEN
    RAISE EXCEPTION
      'Creator score is only % complete. At least 50%% of score components must be filled before an evaluation can be unlocked.',
      completeness;
  END IF;
  RETURN NEW;
END;
$function$


CREATE OR REPLACE FUNCTION public.compute_creator_reliability(p_creator_id uuid)
 RETURNS numeric
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_total_campaigns integer;
  v_verified_campaigns integer;
  v_completion_rate numeric;
  v_has_sponsor_rating boolean;
  v_avg_sponsor_rating numeric;
  v_has_endorsement boolean;
  v_avg_endorsement numeric;
  v_total_sponsors integer;
  v_repeat_sponsors integer;
  v_repeat_rate numeric;
  v_has_would_hire boolean;
  v_would_hire_count integer;
  v_would_hire_yes integer;
  v_would_hire_pct numeric;
  v_weight_used numeric := 0;
  v_score_sum numeric := 0;
  v_reliability numeric;
begin
  select count(*), count(*) filter (where creator_confirmed = true and sponsor_confirmed = true)
  into v_total_campaigns, v_verified_campaigns
  from campaigns where creator_id = p_creator_id;

  if v_total_campaigns = 0 then
    update creators set
      reliability_score = 0, repeat_sponsor_rate = 0, would_hire_again_pct = 0, updated_at = now()
    where id = p_creator_id;
    return 0;
  end if;

  v_completion_rate := (v_verified_campaigns::numeric / v_total_campaigns) * 100;

  select avg(sponsor_rating) * 20, count(*) > 0
  into v_avg_sponsor_rating, v_has_sponsor_rating
  from campaigns where creator_id = p_creator_id and sponsor_rating is not null;
  v_avg_sponsor_rating := coalesce(v_avg_sponsor_rating, 0);

  select avg((coalesce(communication_rating,0) + coalesce(professionalism_rating,0) + coalesce(deliverable_quality_rating,0)) / 3.0) * 20
  into v_avg_endorsement
  from campaigns where creator_id = p_creator_id and endorsement_submitted_at is not null;
  v_has_endorsement := v_avg_endorsement is not null;
  v_avg_endorsement := coalesce(v_avg_endorsement, 0);

  select count(distinct sponsor_id)
  into v_total_sponsors
  from campaigns where creator_id = p_creator_id and creator_confirmed = true and sponsor_confirmed = true;

  select count(*) into v_repeat_sponsors from (
    select sponsor_id from campaigns
    where creator_id = p_creator_id and creator_confirmed = true and sponsor_confirmed = true
    group by sponsor_id having count(*) > 1
  ) sub;

  v_repeat_rate := case when v_total_sponsors > 0 then (v_repeat_sponsors::numeric / v_total_sponsors) * 100 else 0 end;

  select count(*) filter (where would_hire_again is not null),
         count(*) filter (where would_hire_again = true)
  into v_would_hire_count, v_would_hire_yes
  from campaigns where creator_id = p_creator_id;

  v_has_would_hire := v_would_hire_count > 0;
  v_would_hire_pct := case when v_would_hire_count > 0 then (v_would_hire_yes::numeric / v_would_hire_count) * 100 else 0 end;

  v_score_sum := v_completion_rate * 30;
  v_weight_used := 30;

  if v_has_sponsor_rating then
    v_score_sum := v_score_sum + v_avg_sponsor_rating * 25;
    v_weight_used := v_weight_used + 25;
  end if;

  if v_has_endorsement then
    v_score_sum := v_score_sum + v_avg_endorsement * 20;
    v_weight_used := v_weight_used + 20;
  end if;

  if v_total_sponsors > 0 then
    v_score_sum := v_score_sum + v_repeat_rate * 15;
    v_weight_used := v_weight_used + 15;
  end if;

  if v_has_would_hire then
    v_score_sum := v_score_sum + v_would_hire_pct * 10;
    v_weight_used := v_weight_used + 10;
  end if;

  v_reliability := round(v_score_sum / v_weight_used);

  update creators set
    reliability_score = v_reliability,
    repeat_sponsor_rate = round(v_repeat_rate),
    would_hire_again_pct = round(v_would_hire_pct),
    updated_at = now()
  where id = p_creator_id;

  return v_reliability;
end;
$function$


CREATE OR REPLACE FUNCTION public.creator_score_completeness(p_creator_id uuid)
 RETURNS numeric
 LANGUAGE sql
 STABLE
 SET search_path TO 'public'
AS $function$
  SELECT CASE
    WHEN COUNT(*) = 0 THEN 0
    ELSE ROUND(
      COUNT(*) FILTER (WHERE value IS NOT NULL AND value > 0)::NUMERIC
      / COUNT(*)::NUMERIC * 100, 1
    )
  END
  FROM score_components
  WHERE creator_id = p_creator_id;
$function$


CREATE OR REPLACE FUNCTION public.find_sponsor_by_profile_or_stripe(p_stripe_customer_id text, p_profile_id uuid DEFAULT NULL::uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_id UUID;
BEGIN
  SELECT id INTO v_id FROM sponsors WHERE stripe_customer_id = p_stripe_customer_id LIMIT 1;
  IF v_id IS NOT NULL THEN RETURN v_id; END IF;
  IF p_profile_id IS NOT NULL THEN
    SELECT id INTO v_id FROM sponsors WHERE id = p_profile_id LIMIT 1;
  END IF;
  RETURN v_id;
END;
$function$


CREATE OR REPLACE FUNCTION public.fn_admin_apply_brand_safety_scan(p_scan_id uuid, p_decision text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_scan record;
  v_gambling_flagged boolean;
  v_adult_flagged boolean;
  v_other_flagged boolean;
  v_self_gambling numeric;
  v_self_adult numeric;
  v_self_family numeric;
  v_self_other_total numeric;
  v_effective_gambling numeric;
  v_effective_adult numeric;
  v_effective_family numeric;
  v_total numeric;
begin
  if not fn_is_admin() then
    raise exception 'ADMIN_ONLY: only admins can review brand safety scans';
  end if;

  if p_decision not in ('approved', 'rejected') then
    raise exception 'INVALID_DECISION: must be approved or rejected';
  end if;

  select * into v_scan from brand_safety_scans where id = p_scan_id and status = 'pending_review';
  if v_scan is null then
    raise exception 'NOT_FOUND: no pending scan with that id';
  end if;

  if p_decision = 'rejected' then
    update brand_safety_scans set status = 'rejected', reviewed_at = now() where id = p_scan_id;
    return;
  end if;

  v_gambling_flagged := 'gambling' = ANY(v_scan.categories);
  v_adult_flagged := 'adult_content' = ANY(v_scan.categories);
  v_other_flagged := EXISTS (
    SELECT 1 FROM unnest(v_scan.categories) c WHERE c NOT IN ('gambling', 'adult_content')
  );

  SELECT coalesce(sum(p.penalty) FILTER (WHERE a.question_key = 'gambling'), 0),
         coalesce(sum(p.penalty) FILTER (WHERE a.question_key = 'adult'), 0),
         coalesce(sum(p.penalty) FILTER (WHERE a.question_key = 'family_safe'), 0),
         coalesce(sum(p.penalty) FILTER (WHERE a.question_key NOT IN ('gambling', 'adult', 'family_safe')), 0)
    INTO v_self_gambling, v_self_adult, v_self_family, v_self_other_total
    FROM brand_safety_answers a
    JOIN brand_safety_penalties p ON p.question_key = a.question_key AND p.answer = a.answer
    WHERE a.creator_id = v_scan.creator_id;

  v_effective_gambling := CASE WHEN v_gambling_flagged THEN LEAST(coalesce(v_self_gambling,0), -25) ELSE coalesce(v_self_gambling,0) END;
  v_effective_adult := CASE WHEN v_adult_flagged THEN LEAST(coalesce(v_self_adult,0), -30) ELSE coalesce(v_self_adult,0) END;
  v_effective_family := CASE WHEN v_other_flagged THEN LEAST(coalesce(v_self_family,0), -20) ELSE coalesce(v_self_family,0) END;

  v_total := greatest(100 + v_effective_gambling + v_effective_adult + v_effective_family + coalesce(v_self_other_total,0), 0);

  INSERT INTO score_components (creator_id, component_key, label, weight, value, status)
  VALUES (v_scan.creator_id, 'brand_safety', 'Brand safety', 0.20, v_total, 'scan_reviewed')
  ON CONFLICT (creator_id, component_key)
  DO UPDATE SET value = excluded.value, status = 'scan_reviewed', updated_at = now();

  UPDATE brand_safety_scans SET status = 'approved', reviewed_at = now() WHERE id = p_scan_id;
end;
$function$


CREATE OR REPLACE FUNCTION public.fn_admin_flag_creator(p_profile_id uuid, p_reason text)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
declare
  v_admin_id uuid;
begin
  if not fn_is_admin() then
    raise exception 'Admin only';
  end if;
  select id into v_admin_id from profiles where auth_user_id = auth.uid();
  insert into admin_flags (creator_profile_id, flagged_by, reason)
  values (p_profile_id, v_admin_id, p_reason);
end;
$function$


CREATE OR REPLACE FUNCTION public.fn_admin_list_creator_directory()
 RETURNS TABLE(profile_id uuid, display_name text, email text, created_at timestamp with time zone, plan text, trust_score numeric, badge_tier text, founding_cohort boolean, is_flagged boolean)
 LANGUAGE plpgsql
AS $function$
begin
  if not fn_is_admin() then
    raise exception 'Admin only';
  end if;
  return query
    select
      p.id,
      p.display_name,
      p.email,
      p.created_at,
      c.plan::text,
      c.trust_score,
      c.badge_tier::text,
      c.founding_cohort,
      exists(select 1 from admin_flags af where af.creator_profile_id = p.id and af.resolved = false)
    from profiles p
    join creators c on c.id = p.id
    where p.role = 'creator'
    order by p.created_at desc;
end;
$function$


CREATE OR REPLACE FUNCTION public.fn_admin_list_profiles()
 RETURNS SETOF profiles
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
begin
  if not fn_is_admin() then
    raise exception 'Admin only';
  end if;
  return query select * from profiles order by created_at desc;
end;
$function$


CREATE OR REPLACE FUNCTION public.fn_campaign_mutual_confirm()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
begin
  if new.creator_confirmed and new.sponsor_confirmed and old.status != 'verified' then
    new.status := 'verified';
    new.verified_at := now();
  end if;
  return new;
end;
$function$


CREATE OR REPLACE FUNCTION public.fn_capture_trust_score_at_approval()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.approval_status = 'approved' AND (OLD.approval_status IS DISTINCT FROM 'approved') THEN
    SELECT trust_score INTO NEW.trust_score_at_approval FROM creators WHERE id = NEW.creator_id;
  END IF;
  RETURN NEW;
END;
$function$


CREATE OR REPLACE FUNCTION public.fn_capture_trust_score_history()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.trust_score IS DISTINCT FROM OLD.trust_score
     OR NEW.confidence IS DISTINCT FROM OLD.confidence THEN
    INSERT INTO trust_score_history (creator_id, trust_score, confidence, recorded_at)
    VALUES (NEW.id, NEW.trust_score, NEW.confidence, now());
  END IF;
  RETURN NEW;
END;
$function$


CREATE OR REPLACE FUNCTION public.fn_claim_free_eval_unlock(p_sponsor_id uuid)
 RETURNS TABLE(claimed boolean, new_used integer)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_new_used integer;
BEGIN
  UPDATE sponsors
  SET evals_used_this_period = evals_used_this_period + 1
  WHERE id = p_sponsor_id
    AND plan = 'starter'
    AND evals_used_this_period < 25
  RETURNING evals_used_this_period INTO v_new_used;

  IF v_new_used IS NOT NULL THEN
    RETURN QUERY SELECT true, v_new_used;
  ELSE
    RETURN QUERY SELECT false, NULL::integer;
  END IF;
END;
$function$


CREATE OR REPLACE FUNCTION public.fn_confidence_on_evidence_change()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  PERFORM fn_recalc_creator_confidence(COALESCE(NEW.creator_id, OLD.creator_id));
  RETURN NEW;
END;
$function$


CREATE OR REPLACE FUNCTION public.fn_confidence_on_platform_connection_change()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  PERFORM fn_recalc_creator_confidence(COALESCE(NEW.creator_id, OLD.creator_id));
  RETURN NEW;
END;
$function$


CREATE OR REPLACE FUNCTION public.fn_confirm_campaign_invite(p_token text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_invite record;
  v_sponsor_profile record;
  v_auth_email text;
  v_campaign_id uuid;
BEGIN
  SELECT * INTO v_invite FROM campaign_confirmation_invites WHERE token = p_token;
  IF v_invite IS NULL THEN
    RAISE EXCEPTION 'Invite not found';
  END IF;

  IF v_invite.status = 'confirmed' THEN
    RETURN v_invite.campaign_id;
  END IF;

  IF v_invite.expires_at < now() THEN
    UPDATE campaign_confirmation_invites SET status = 'expired' WHERE id = v_invite.id;
    RAISE EXCEPTION 'This invite has expired';
  END IF;

  SELECT p.* INTO v_sponsor_profile
  FROM profiles p
  WHERE p.auth_user_id = auth.uid() AND p.role = 'sponsor';

  IF v_sponsor_profile IS NULL THEN
    RAISE EXCEPTION 'Not authenticated as a sponsor';
  END IF;

  v_auth_email := auth.jwt() ->> 'email';

  IF v_auth_email IS NULL OR lower(v_auth_email) IS DISTINCT FROM lower(v_invite.sponsor_email) THEN
    RAISE EXCEPTION 'This invite was sent to a different email address';
  END IF;

  INSERT INTO campaigns (creator_id, sponsor_id, name, creator_confirmed, sponsor_confirmed, status, budget_range, objective, verified_at)
  VALUES (
    v_invite.creator_id,
    v_sponsor_profile.id,
    COALESCE(v_invite.description, 'Confirmed campaign'),
    true, true, 'verified',
    v_invite.budget_range,
    v_invite.description,
    now()
  )
  RETURNING id INTO v_campaign_id;

  UPDATE campaign_confirmation_invites
  SET status = 'confirmed', confirmed_at = now(), campaign_id = v_campaign_id
  WHERE id = v_invite.id;

  RETURN v_campaign_id;
END;
$function$


CREATE OR REPLACE FUNCTION public.fn_creator_platform_summary(p_creator_id uuid)
 RETURNS TABLE(platform text, platform_handle text, verification_method text, follower_count bigint, video_count bigint, view_count bigint, last_synced_at timestamp with time zone, connected_at timestamp with time zone)
 LANGUAGE sql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT platform, platform_handle, verification_method,
         follower_count, video_count, view_count,
         last_synced_at, connected_at
  FROM public.platform_connections
  WHERE creator_id = p_creator_id;
$function$


CREATE OR REPLACE FUNCTION public.fn_current_profile_id()
 RETURNS uuid
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  select id from profiles where auth_user_id = auth.uid();
$function$


CREATE OR REPLACE FUNCTION public.fn_current_role()
 RETURNS user_role
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  select role from profiles where auth_user_id = auth.uid();
$function$


CREATE OR REPLACE FUNCTION public.fn_enforce_platform_cap()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_is_unlimited boolean;
  v_new_platform text;
  v_existing_platforms text[];
BEGIN
  SELECT (plan = 'pro' OR founding_cohort) INTO v_is_unlimited
  FROM creators WHERE id = NEW.creator_id;

  IF v_is_unlimited THEN
    RETURN NEW;
  END IF;

  v_new_platform := lower(NEW.platform);
  IF v_new_platform IS NULL OR v_new_platform = '' THEN
    RETURN NEW;
  END IF;

  SELECT array_agg(DISTINCT lower(platform)) INTO v_existing_platforms
  FROM platform_connections
  WHERE creator_id = NEW.creator_id AND verification_method = 'oauth';

  IF v_existing_platforms IS NOT NULL
     AND array_length(v_existing_platforms, 1) >= 1
     AND NOT (v_new_platform = ANY(v_existing_platforms)) THEN
    RAISE EXCEPTION 'PLATFORM_CAP: Free plan is limited to one OAuth-verified platform. Upgrade to Pro for unlimited platforms.';
  END IF;

  RETURN NEW;
END;
$function$


CREATE OR REPLACE FUNCTION public.fn_enforce_team_cap()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF fn_owned_team_count(NEW.owner_id) >= 3 THEN
    RAISE EXCEPTION 'You can own a maximum of 3 active teams. Archive one before creating another.';
  END IF;
  RETURN NEW;
END;
$function$


CREATE OR REPLACE FUNCTION public.fn_enforce_watchlist_limit()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  sponsor_plan plan_tier;
  current_count int;
  max_allowed int;
begin
  select plan into sponsor_plan from sponsors where id = new.sponsor_id;
  max_allowed := case when sponsor_plan = 'free' then 3 else null end;

  if max_allowed is not null then
    select count(*) into current_count from watchlists where sponsor_id = new.sponsor_id;
    if current_count >= max_allowed then
      raise exception 'Free plan is limited to % saved creators. Upgrade to save more.', max_allowed;
    end if;
  end if;

  return new;
end;
$function$


CREATE OR REPLACE FUNCTION public.fn_flag_failed_notification()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_req record;
begin
  select * into v_req from public.notification_requests where net_request_id = new.id;
  if v_req.net_request_id is null then
    return new;
  end if;

  if new.timed_out is true or new.status_code is null or new.status_code < 200 or new.status_code >= 300 then
    insert into public.notification_failures (kind, recipient_email, error, attempts, created_at, last_attempted_at)
    values (
      v_req.kind,
      v_req.recipient_email,
      coalesce(new.error_msg, 'HTTP ' || coalesce(new.status_code::text, 'no response')) || (case when new.timed_out then ' (timed out)' else '' end),
      1, now(), now()
    );
  end if;

  delete from public.notification_requests where net_request_id = new.id;
  return new;
end;
$function$


CREATE OR REPLACE FUNCTION public.fn_generate_creator_slug()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
DECLARE
  v_display_name text;
  v_base text;
  v_slug text;
BEGIN
  IF new.slug IS NOT NULL THEN
    RETURN new;
  END IF;

  SELECT display_name INTO v_display_name FROM profiles WHERE id = new.id;
  v_base := lower(regexp_replace(coalesce(v_display_name, 'creator'), '[^a-zA-Z0-9]+', '-', 'g'));
  v_base := trim(both '-' from v_base);
  IF v_base = '' THEN v_base := 'creator'; END IF;

  v_slug := v_base || '-' || substr(encode(gen_random_bytes(3), 'hex'), 1, 5);
  WHILE EXISTS(SELECT 1 FROM creators WHERE slug = v_slug) LOOP
    v_slug := v_base || '-' || substr(encode(gen_random_bytes(3), 'hex'), 1, 5);
  END LOOP;

  new.slug := v_slug;
  RETURN new;
END;
$function$


CREATE OR REPLACE FUNCTION public.fn_get_evekit_profile(p_slug text)
 RETURNS TABLE(display_name text, niche text, location text, bio text, business_email text, avatar_url text, gallery_images jsonb, available_for text[], causes text[], theme text, trust_score numeric, confidence numeric, badge_tier text, founding_cohort boolean, reliability_score numeric, verified_campaign_count bigint, profile_views integer, audience_countries jsonb, audience_genders jsonb, audience_ages jsonb, platforms jsonb, campaigns jsonb, collaborations jsonb, press_mentions jsonb)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT
    p.display_name, c.niche, c.location, c.bio, c.business_email,
    c.avatar_url, c.gallery_images, c.available_for, c.causes, c.theme,
    c.trust_score, c.confidence::numeric, c.badge_tier, c.founding_cohort,
    c.reliability_score,
    (SELECT count(*) FROM campaigns cam WHERE cam.creator_id = c.id AND cam.creator_confirmed AND cam.sponsor_confirmed),
    c.profile_views,
    COALESCE(
      (SELECT jsonb_agg(jsonb_build_object('label', ad.label, 'pct', ad.pct) ORDER BY ad.pct DESC)
       FROM audience_demographics ad WHERE ad.creator_id = c.id AND ad.dimension = 'country'),
      '[]'::jsonb
    ),
    COALESCE(
      (SELECT jsonb_agg(jsonb_build_object('label', ad.label, 'pct', ad.pct) ORDER BY ad.pct DESC)
       FROM audience_demographics ad WHERE ad.creator_id = c.id AND ad.dimension = 'gender'),
      '[]'::jsonb
    ),
    COALESCE(
      (SELECT jsonb_agg(jsonb_build_object('label', ad.label, 'pct', ad.pct) ORDER BY ad.pct DESC)
       FROM audience_demographics ad WHERE ad.creator_id = c.id AND ad.dimension = 'age'),
      '[]'::jsonb
    ),
    COALESCE(
      (SELECT jsonb_agg(jsonb_build_object(
         'platform', pc.platform, 'platform_handle', pc.platform_handle,
         'follower_count', pc.follower_count, 'video_count', pc.video_count,
         'view_count', pc.view_count, 'verification_method', pc.verification_method
       ) ORDER BY pc.follower_count DESC NULLS LAST)
       FROM platform_connections pc WHERE pc.creator_id = c.id AND pc.follower_count IS NOT NULL),
      '[]'::jsonb
    ),
    COALESCE(
      (SELECT jsonb_agg(jsonb_build_object(
         'name', cam.name, 'objective', cam.objective, 'completed_at', cam.completed_at
       ) ORDER BY cam.created_at DESC)
       FROM (
         SELECT * FROM campaigns cam2
         WHERE cam2.creator_id = c.id AND cam2.creator_confirmed AND cam2.sponsor_confirmed
         ORDER BY cam2.created_at DESC
         LIMIT 6
       ) cam),
      '[]'::jsonb
    ),
    COALESCE(
      (SELECT jsonb_agg(jsonb_build_object(
         'brand_name', cc.brand_name, 'logo_url', cc.logo_url, 'link', cc.link
       ) ORDER BY cc.display_order, cc.created_at)
       FROM creator_collaborations cc WHERE cc.creator_id = c.id),
      '[]'::jsonb
    ),
    COALESCE(
      (SELECT jsonb_agg(jsonb_build_object(
         'id', cpm.id, 'title', cpm.title, 'outlet_name', cpm.outlet_name,
         'url', cpm.url, 'mention_date', cpm.mention_date
       ) ORDER BY cpm.display_order, cpm.created_at)
       FROM creator_press_mentions cpm WHERE cpm.creator_id = c.id),
      '[]'::jsonb
    )
  FROM creators c
  JOIN profiles p ON p.id = c.id
  WHERE c.slug = p_slug AND c.is_test = false;
$function$


