CREATE OR REPLACE FUNCTION public.fn_recalc_badge_tier()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
declare
  verified_count int;
  new_tier text;
begin
  select count(*) into verified_count from campaigns
    where creator_id = coalesce(new.creator_id, old.creator_id) and status = 'verified';
  new_tier := case
    when verified_count >= 20 then 'platinum'
    when verified_count >= 10 then 'gold'
    when verified_count >= 5 then 'silver'
    when verified_count >= 2 then 'bronze'
    else 'none'
  end;
  update creators set badge_tier = new_tier, updated_at = now()
    where id = coalesce(new.creator_id, old.creator_id);
  return new;
end;
$function$


CREATE OR REPLACE FUNCTION public.fn_recalc_brand_safety()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  target_creator uuid := coalesce(new.creator_id, old.creator_id);
  total numeric;
begin
  select 100 + coalesce(sum(p.penalty), 0) into total
    from brand_safety_answers a
    join brand_safety_penalties p on p.question_key = a.question_key and p.answer = a.answer
    where a.creator_id = target_creator;

  total := greatest(total, 0);

  insert into score_components (creator_id, component_key, label, weight, value, status)
  values (target_creator, 'brand_safety', 'Brand safety', 0.20, total, 'self_reported')
  on conflict (creator_id, component_key)
  do update set value = excluded.value, status = 'self_reported', updated_at = now();

  return new;
end;
$function$


CREATE OR REPLACE FUNCTION public.fn_recalc_creator_confidence(p_creator_id uuid)
 RETURNS numeric
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_completeness numeric;
  v_verified_campaigns integer;
  v_sample_size numeric;
  v_evidence_total integer;
  v_evidence_verified integer;
  v_connections_total integer;
  v_connections_verified integer;
  v_verification_depth numeric;
  v_confidence numeric;
BEGIN
  v_completeness := creator_score_completeness(p_creator_id);

  SELECT COUNT(*) INTO v_verified_campaigns
  FROM campaigns WHERE creator_id = p_creator_id AND creator_confirmed = true AND sponsor_confirmed = true;
  v_sample_size := LEAST(v_verified_campaigns::numeric / 10, 1) * 100;

  SELECT COUNT(*), COUNT(*) FILTER (WHERE status = 'live_verified')
  INTO v_evidence_total, v_evidence_verified
  FROM evidence_uploads WHERE creator_id = p_creator_id;

  SELECT COUNT(*), COUNT(*) FILTER (WHERE verification_method = 'oauth')
  INTO v_connections_total, v_connections_verified
  FROM platform_connections WHERE creator_id = p_creator_id;

  v_verification_depth := CASE WHEN (v_evidence_total + v_connections_total) > 0
    THEN ((v_evidence_verified + v_connections_verified)::numeric / (v_evidence_total + v_connections_total)) * 100
    ELSE 0 END;

  v_confidence := ROUND(
    (v_completeness * 0.40) +
    (v_sample_size * 0.30) +
    (v_verification_depth * 0.30)
  );

  UPDATE creators SET confidence = v_confidence, updated_at = now() WHERE id = p_creator_id;
  RETURN v_confidence;
END;
$function$


CREATE OR REPLACE FUNCTION public.fn_recalc_engagement_quality_youtube()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_ratio numeric;
  v_value numeric;
begin
  if new.follower_count is null or new.follower_count = 0
     or new.video_count is null or new.video_count = 0
     or new.view_count is null then
    return new;
  end if;

  v_ratio := (new.view_count::numeric / new.video_count) / new.follower_count;

  v_value := case
    when v_ratio >= 1.0  then 90
    when v_ratio >= 0.5  then 80
    when v_ratio >= 0.2  then 70
    when v_ratio >= 0.05 then 55
    else 40
  end;

  insert into score_components (creator_id, component_key, label, weight, value, status)
  values (new.creator_id, 'engagement_quality_youtube', 'Engagement quality (YouTube)', 0.20, v_value, 'live_verified')
  on conflict (creator_id, component_key)
  do update set value = excluded.value, weight = excluded.weight, status = 'live_verified', updated_at = now();

  return new;
end;
$function$


CREATE OR REPLACE FUNCTION public.fn_recalc_evidence_component()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  target_creator uuid := new.creator_id;
  target_component text;
  approved_count integer;
  v_value numeric;
begin
  if new.status is distinct from 'live_verified' or old.status = 'live_verified' then
    return new;
  end if;

  target_component := case new.evidence_type
    when 'Audience' then 'audience_authenticity'
    when 'Analytics' then 'engagement_quality'
    when 'Campaign' then 'content_consistency'
    else null
  end;

  if target_component is null then
    return new;
  end if;

  select count(*) into approved_count
  from evidence_uploads
  where creator_id = target_creator
    and evidence_type = new.evidence_type
    and status = 'live_verified';

  v_value := least(85, 50 + 15 * approved_count);

  insert into score_components (creator_id, component_key, label, weight, value, status)
  values (
    target_creator,
    target_component,
    initcap(replace(target_component, '_', ' ')),
    0.20,
    v_value,
    'evidence_submitted'
  )
  on conflict (creator_id, component_key)
  do update set
    value = excluded.value,
    status = case when score_components.status = 'live_verified' then score_components.status else 'evidence_submitted' end,
    updated_at = now();

  return new;
end;
$function$


CREATE OR REPLACE FUNCTION public.fn_recalc_professionalism()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  target_creator uuid := new.creator_id;
  v_avg numeric;
begin
  select coalesce(avg(professionalism_rating), 0) * 20
  into v_avg
  from campaigns
  where creator_id = target_creator
    and endorsement_submitted_at is not null;

  insert into score_components (creator_id, component_key, label, weight, value, status)
  values (target_creator, 'professionalism', 'Professionalism', 0.20, v_avg, 'live_verified')
  on conflict (creator_id, component_key)
  do update set value = excluded.value, status = 'live_verified', updated_at = now();

  return new;
end;
$function$


CREATE OR REPLACE FUNCTION public.fn_recalc_trust_score()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
declare
  total numeric;
  v_creator_id uuid;
begin
  v_creator_id := coalesce(new.creator_id, old.creator_id);
  select coalesce(sum(value * weight), 0) into total
    from score_components where creator_id = v_creator_id;
  update creators set trust_score = round(total, 0), updated_at = now()
    where id = v_creator_id;
  perform fn_recalc_creator_confidence(v_creator_id);
  return new;
end;
$function$


CREATE OR REPLACE FUNCTION public.fn_set_evekit_slug(p_slug text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_creator_id uuid := fn_current_profile_id();
  v_plan text;
  v_clean text := lower(trim(p_slug));
BEGIN
  IF v_creator_id IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Not signed in.');
  END IF;

  SELECT plan INTO v_plan FROM public.creators WHERE id = v_creator_id;
  IF v_plan IS DISTINCT FROM 'pro' THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Custom vanity URLs are a Pro feature.');
  END IF;

  IF v_clean !~ '^[a-z0-9-]{3,40}$' THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Use 3-40 lowercase letters, numbers, or hyphens only.');
  END IF;

  IF EXISTS (SELECT 1 FROM public.creators WHERE slug = v_clean AND id <> v_creator_id) THEN
    RETURN jsonb_build_object('ok', false, 'error', 'That URL is already taken.');
  END IF;

  UPDATE public.creators SET slug = v_clean, updated_at = now() WHERE id = v_creator_id;
  RETURN jsonb_build_object('ok', true, 'slug', v_clean);
END;
$function$


