CREATE OR REPLACE FUNCTION public.fn_team_notes(p_team_id uuid)
 RETURNS TABLE(note_id uuid, author_id uuid, author_display_name text, creator_id uuid, creator_display_name text, content text, created_at timestamp with time zone)
 LANGUAGE sql
 STABLE SECURITY DEFINER
