CREATE OR REPLACE FUNCTION public.fn_team_score_alerts(p_team_id uuid)
 RETURNS TABLE(evaluation_id uuid, creator_id uuid, creator_name text, score_then numeric, score_now numeric, approved_at timestamp with time zone)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT e.id, c.id, p.display_name, e.trust_score_at_approval, c.trust_score, e.reviewed_at
  FROM evaluations e
  JOIN creators c ON c.id = e.creator_id
  JOIN profiles p ON p.id = c.id
  WHERE e.team_id = p_team_id
    AND fn_is_team_member(p_team_id)
    AND e.approval_status = 'approved'
    AND e.trust_score_at_approval IS NOT NULL
    AND c.trust_score < e.trust_score_at_approval
  ORDER BY (e.trust_score_at_approval - c.trust_score) DESC;
$function$


CREATE OR REPLACE FUNCTION public.fn_validate_campaign_confirmation()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
begin
  if fn_is_admin() then
    return new;
  end if;

  if new.sponsor_confirmed is distinct from old.sponsor_confirmed
     and new.sponsor_id != fn_current_profile_id() then
    raise exception 'Only the sponsor on this campaign can set sponsor_confirmed';
  end if;
  if new.creator_confirmed is distinct from old.creator_confirmed
     and new.creator_id != fn_current_profile_id() then
    raise exception 'Only the creator on this campaign can set creator_confirmed';
  end if;

  if new.status is distinct from old.status then
    if new.status = 'verified' then
      if not (new.creator_confirmed and new.sponsor_confirmed) then
        raise exception 'Campaigns can only become verified once both parties confirm';
      end if;
    elsif new.status = 'disputed' then
      if old.status != 'pending' then
        raise exception 'Only a pending campaign can be disputed';
      end if;
      if new.creator_id != fn_current_profile_id() then
        raise exception 'Only the creator on this campaign can dispute it';
      end if;
      if old.creator_confirmed then
        raise exception 'A campaign you already confirmed cannot be disputed';
      end if;
      new.disputed_at := now();
    elsif new.status = 'pending' and old.status = 'disputed' then
      if new.creator_id != old.creator_id or new.sponsor_id != old.sponsor_id then
        raise exception 'A disputed campaign cannot be reassigned to a different creator or sponsor';
      end if;
      if fn_current_profile_id() != old.creator_id and fn_current_profile_id() != old.sponsor_id then
        raise exception 'Only the creator or sponsor on this campaign can resolve a dispute';
      end if;
      new.dispute_reason := null;
      new.disputed_at := null;
    else
      raise exception 'Invalid campaign status transition';
    end if;
  end if;

  return new;
end;
$function$


CREATE OR REPLACE FUNCTION public.fn_validate_creator_rating()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
begin
  if fn_is_admin() then
    return new;
  end if;

  if (new.creator_rating is distinct from old.creator_rating)
     or (new.creator_outcome is distinct from old.creator_outcome) then

    if new.creator_id != fn_current_profile_id() then
      raise exception 'Only the creator on this campaign can rate the sponsor';
    end if;
    if old.status != 'verified' then
      raise exception 'Sponsor ratings can only be submitted on verified campaigns';
    end if;
  end if;

  return new;
end;
$function$


CREATE OR REPLACE FUNCTION public.fn_validate_endorsement()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
begin
  if fn_is_admin() then
    return new;
  end if;

  if (new.sponsor_rating is distinct from old.sponsor_rating)
     or (new.communication_rating is distinct from old.communication_rating)
     or (new.professionalism_rating is distinct from old.professionalism_rating)
     or (new.deliverable_quality_rating is distinct from old.deliverable_quality_rating)
     or (new.would_hire_again is distinct from old.would_hire_again)
     or (new.endorsement_notes is distinct from old.endorsement_notes)
     or (new.endorsement_public_consent is distinct from old.endorsement_public_consent)
     or (new.endorsement_submitted_at is distinct from old.endorsement_submitted_at) then

    if new.sponsor_id != fn_current_profile_id() then
      raise exception 'Only the sponsor on this campaign can submit an endorsement';
    end if;
    if old.status != 'verified' then
      raise exception 'Endorsements can only be submitted on verified campaigns';
    end if;
    if old.endorsement_submitted_at is not null then
      raise exception 'Endorsement already submitted for this campaign';
    end if;
  end if;

  return new;
end;
$function$


CREATE OR REPLACE FUNCTION public.fn_validate_evaluation_approval()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
  IF fn_is_admin() THEN
    RETURN NEW;
  END IF;

  IF NEW.approval_status IS DISTINCT FROM OLD.approval_status THEN
    IF NEW.approval_status IN ('approved', 'rejected') THEN
      IF NOT EXISTS (
        SELECT 1 FROM teams WHERE teams.id = NEW.team_id AND teams.owner_id = fn_current_profile_id()
      ) THEN
        RAISE EXCEPTION 'Only the team owner can approve or reject an evaluation';
      END IF;
    END IF;
  END IF;

  RETURN NEW;
END;
$function$


CREATE OR REPLACE FUNCTION public.fn_validate_evidence_status()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
begin
  if fn_is_admin() then
    return new;
  end if;

  if new.status is distinct from old.status then
    raise exception 'Only an admin can change evidence review status';
  end if;

  return new;
end;
$function$


CREATE OR REPLACE FUNCTION public.handle_new_auth_user()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_role text := new.raw_user_meta_data->>'role';
  v_display_name text := new.raw_user_meta_data->>'display_name';
  v_profile_id uuid;
begin
  if new.email_confirmed_at is null then
    return new;
  end if;

  if v_role is null or v_display_name is null then
    return new;
  end if;

  insert into public.profiles (auth_user_id, role, display_name, email)
  values (new.id, v_role::user_role, v_display_name, new.email)
  on conflict (auth_user_id) do nothing
  returning id into v_profile_id;

  if v_profile_id is null then
    select id into v_profile_id from public.profiles where auth_user_id = new.id;
  end if;

  if v_role = 'creator' then
    insert into public.creators (id) values (v_profile_id) on conflict (id) do nothing;
  elsif v_role = 'sponsor' then
    insert into public.sponsors (id, company_name) values (v_profile_id, v_display_name) on conflict (id) do nothing;
  end if;

  return new;
end;
$function$


CREATE OR REPLACE FUNCTION public.recalculate_sponsor_reliability(p_sponsor_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
DECLARE
  total_confirmed INTEGER;
  score NUMERIC;
  reliability TEXT;
BEGIN
  SELECT COUNT(*) INTO total_confirmed
  FROM campaigns
  WHERE sponsor_id = p_sponsor_id
    AND creator_confirmed = TRUE
    AND sponsor_confirmed = TRUE;

  score := LEAST(total_confirmed * 10, 100);

  reliability := CASE
    WHEN total_confirmed = 0 THEN 'unrated'
    WHEN total_confirmed < 3 THEN 'new'
    WHEN score >= 80 THEN 'trusted'
    WHEN score >= 50 THEN 'established'
    ELSE 'building'
  END;

  UPDATE sponsors
  SET
    reliability_score = score,
    campaigns_completed = total_confirmed,
    payment_reliability = reliability,
    updated_at = now()
  WHERE id = p_sponsor_id;
END;
$function$


CREATE OR REPLACE FUNCTION public.trg_confidence_on_campaign_verified()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
begin
  perform fn_recalc_creator_confidence(coalesce(new.creator_id, old.creator_id));
  return new;
end;
$function$


CREATE OR REPLACE FUNCTION public.trg_sponsor_reliability_on_campaign()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.creator_confirmed = TRUE AND NEW.sponsor_confirmed = TRUE
     AND (OLD.creator_confirmed = FALSE OR OLD.sponsor_confirmed = FALSE) THEN
    PERFORM recalculate_sponsor_reliability(NEW.sponsor_id);
  END IF;
  RETURN NEW;
END;
$function$


CREATE OR REPLACE FUNCTION public.trigger_reliability_on_endorsement()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.endorsement_submitted_at IS NOT NULL AND (
       OLD.endorsement_submitted_at IS NULL
       OR OLD.sponsor_rating IS DISTINCT FROM NEW.sponsor_rating
       OR OLD.communication_rating IS DISTINCT FROM NEW.communication_rating
       OR OLD.professionalism_rating IS DISTINCT FROM NEW.professionalism_rating
       OR OLD.deliverable_quality_rating IS DISTINCT FROM NEW.deliverable_quality_rating
       OR OLD.would_hire_again IS DISTINCT FROM NEW.would_hire_again
  ) THEN
    PERFORM compute_creator_reliability(NEW.creator_id);
  END IF;
  RETURN NEW;
END;
$function$


CREATE OR REPLACE FUNCTION public.trigger_reliability_on_verification()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.creator_confirmed = true AND NEW.sponsor_confirmed = true
     AND (OLD.creator_confirmed = false OR OLD.sponsor_confirmed = false) THEN
    PERFORM compute_creator_reliability(NEW.creator_id);
  END IF;
  RETURN NEW;
END;
$function$


